generated_oml:
// Sensing Components
instance HokuyoUST110LXLidar : DTDFVocab:SensingComponent [
    base:desc "Hokuyo UST110LX LiDAR supplying 3D point‑cloud data at 10 Hz."
    DTDFVocab:producedData LiDARPointCloudTransmitted
]

instance IntelD435iDepthCam : DTDFVocab:SensingComponent [
    base:desc "Intel D435i depth camera providing synchronized RGBD imagery at 30 fps."
    DTDFVocab:producedData DepthImageTransmitted
]

instance VehicleSpeedSensor : DTDFVocab:SensingComponent [
    base:desc "Vehicle speed sensor (RPM/velocity) on the automated drivetrain, polling at 20 Hz."
    DTDFVocab:producedData SpeedTransmitted
]

instance SteeringAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Steering angle sensor measuring servo angle with 0.1° resolution, sampled at 50 Hz."
    DTDFVocab:producedData SteeringAngleTransmitted
]

// Physical‑to‑Virtual Interaction: Data Transmitted
instance LiDARPointCloudTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom HokuyoUST110LXLidar
]
instance DepthImageTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom IntelD435iDepthCam
]
instance SpeedTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom VehicleSpeedSensor
]
instance SteeringAngleTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SteeringAngleSensor
]

// Data Back‑to‑Domain
instance LiDARPointCloudData : DTDFVocab:Data [
    base:desc "Serialized, timestamped 3‑D point‑cloud from the LiDAR."
    DTDFVocab:inputTo LiDARClusterEnabler
    DTDFVocab:fromData LiDARPointCloudTransmitted
]
instance DepthImageData : DTDFVocab:Data [
    base:desc "RGBD image stream from the Intel D435i camera, used for semantic segmentation."
    DTDFVocab:inputTo TrackingEnabler
    DTDFVocab:fromData DepthImageTransmitted
]
instance SpeedData : DTDFVocab:Data [
    base:desc "Vehicle speed measurements in m/s, used for ACC decision."
    DTDFVocab:inputTo ACCOffloadingEnabler
    DTDFVocab:fromData SpeedTransmitted
]
instance SteeringAngleData : DTDFVocab:Data [
    base:desc "Current steering angle in radians, forwarded to actuation control."
    DTDFVocab:inputTo AdjustDesiredSpeedAction
    DTDFVocab:fromData SteeringAngleTransmitted
]

// Models / Data
instance DBSCANPointCloudClusteringModel : DTDFVocab:Model [
    base:desc "DBSCAN clustering on raw LiDAR point‑cloud to identify obstacle clusters."
    DTDFVocab:inputTo LiDARClusterEnabler
]
instance KalmanFilterTrackingModel : DTDFVocab:Model [
    base:desc "Kalman‑filter tracking of detected obstacles based on successive point‑cloud clusters."
    DTDFVocab:inputTo TrackingEnabler
]
instance ACCDistanceLogicModel : DTDFVocab:Model [
    base:desc "Adaptive Cruise Control logic following ISO 15622, computing desired speed."
    DTDFVocab:inputTo ACCOffloadingEnabler
]
instance CAD3DRenderingModel : DTDFVocab:Model [
    base:desc "3‑D CAD and mesh representation of vehicle state and environment for virtual cockpit."
    DTDFVocab:inputTo VisualizationRenderingEnabler
]

// Enablers
instance LiDARClusterEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 node managing DBSCAN clustering on LiDAR data."
    DTDFVocab:enables ClusteringService
]
instance TrackingEnabler : DTDFVocab:Enabler [
    base:desc "ROS2 node executing Kalman‑filter object tracking."
    DTDFVocab:enables TrackingService
]
instance ACCOffloadingEnabler : DTDFVocab:Enabler [
    base:desc "Computation Offloading enabler for ACC logic, invoking cloud service."
    DTDFVocab:enables ComputationOffloadingService
]
instance UIDataMonitoringEnabler : DTDFVocab:Enabler [
    base:desc "Interface node collecting telemetry for UI dashboard."
    DTDFVocab:enables DataMonitoringService
]
instance VisualizationRenderingEnabler : DTDFVocab:Enabler [
    base:desc "Node integrating CAD model into the virtual cockpit renderer."
    DTDFVocab:enables VisualizationService
]
instance RemoteOperatorEnabler : DTDFVocab:Enabler [
    base:desc "OpenAPI‑based remote management interface for ACC control and emergency braking."
    DTDFVocab:enables RemoteManagementService
]
instance ActuationCommandEnabler : DTDFVocab:Enabler [
    base:desc "Translator node converting desired speed and steering commands to actuation voltages."
    DTDFVocab:enables MotorActuationComponent, SteeringActuationComponent, EmergencyBrakingActuationComponent
]

// Services
instance ClusteringService : DTDFVocab:Service [
    base:desc "Service performing obstacle clustering from point‑clouds."
    DTDFVocab:provides ObjectTracksInsight
]
instance TrackingService : DTDFVocab:Service [
    base:desc "Service tracking object positions over time."
    DTDFVocab:provides ObjectTracksInsight
]
instance ComputationOffloadingService : DTDFVocab:Service [
    base:desc "Cloud service executing ACC decision logic and computing desired speed."
    DTDFVocab:provides ACCDecisionInsight
]
instance DataMonitoringService : DTDFVocab:Service [
    base:desc "Real‑time UI dashboards, data logging, and report generation."
    DTDFVocab:provides SpeedInsight, SteeringAngleInsight, DashboardPerformanceInsight, MaintenanceReportInsight
]
instance VisualizationService : DTDFVocab:Service [
    base:desc "3‑D visualization of vehicle state and projected driving path in the virtual cockpit."
    DTDFVocab:provides ObjectTracksInsight
]
instance RemoteManagementService : DTDFVocab:Service [
    base:desc "Enables enable/disable ACC, adjust desired speed, trigger emergency braking."
    DTDFVocab:provides EnableACCAction, DisableACCAction, AdjustDesiredSpeedAction, TriggerEmergencyBrakingAction
]

// Insights
instance SpeedInsight : DTDFVocab:Insight [
    base:desc "Real‑time vehicle speed displayed on UI dashboard."
]
instance SteeringAngleInsight : DTDFVocab:Insight [
    base:desc "Real‑time steering angle displayed on UI dashboard."
]
instance ObjectTracksInsight : DTDFVocab:Insight [
    base:desc "Annotated object tracks from LiDAR and tracking models."
]
instance ACCDecisionInsight : DTDFVocab:Insight [
    base:desc "Estimated desired speed and lead vehicle detection for ACC."
]
instance DashboardPerformanceInsight : DTDFVocab:Insight [
    base:desc "System performance metrics and latency of telemetry streams."
]
instance MaintenanceReportInsight : DTDFVocab:Insight [
    base:desc "Automated report summarizing braking and motor health over time."
]

