    base:desc "Remote operator action to enable Adaptive Cruise Control."
    DTDFVocab:IsAutomatic false
]
instance DisableACCAction : DTDFVocab:Action [
    base:desc "Remote operator action to disable Adaptive Cruise Control."
    DTDFVocab:IsAutomatic false
]
instance AdjustDesiredSpeedAction : DTDFVocab:Action [
    base:desc "Remote operator action to change desired speed target."
    DTDFVocab:IsAutomatic false
]
instance TriggerEmergencyBrakingAction : DTDFVocab:Action [
    base:desc "Emergency braking command transmitted to vehicle braking system."
    DTDFVocab:IsAutomatic false
]
instance ResetDashboardAction : DTDFVocab:Action [
    base:desc "System action to reset UI dashboard to default state."
    DTDFVocab:IsAutomatic true
]

// Acting Components
instance MotorActuationComponent : DTDFVocab:ActingComponent [
    base:desc "Digital Twin component translating velocity commands into motor voltage signals sent to Vedder Electronic Speed Controller."
]
instance SteeringActuationComponent : DTDFVocab:ActingComponent [
    base:desc "Servo actuation component applying steering angle commands received from Digital Twin."
]
instance EmergencyBrakingActuationComponent : DTDFVocab:ActingComponent [
    base:desc "Actuator sending emergency braking command to vehicle braking system."
]

// Environment
instance PhysicalEnvironment : DTDFVocab:Environment [
    base:contains HokuyoUST110LXLidar, IntelD435iDepthCam, VehicleSpeedSensor, SteeringAngleSensor, MotorActuationComponent, SteeringActuationComponent, EmergencyBrakingActuationComponent
]

